'use client'

import { motion } from 'framer-motion'
import { useEffect, useState } from 'react'
import { Leaf, Users, TrendingUp, Heart } from 'lucide-react'

function AnimatedCounter({ value, suffix }) {
  const [displayValue, setDisplayValue] = useState(0)

  useEffect(() => {
    let start = 0
    const increment = value / 50
    const interval = setInterval(() => {
      start += increment
      if (start >= value) {
        setDisplayValue(value)
        clearInterval(interval)
      } else {
        setDisplayValue(Math.floor(start))
      }
    }, 30)
    return () => clearInterval(interval)
  }, [value])

  return (
    <span>
      {displayValue.toLocaleString()}
      {suffix}
    </span>
  )
}

export function StatCard({ icon, label, value, suffix, trend, color, delay = 0 }) {
  const colorClasses = {
    emerald: 'from-emerald-500/20 to-teal-500/20 border-emerald-500/20',
    blue: 'from-blue-500/20 to-cyan-500/20 border-blue-500/20',
    purple: 'from-purple-500/20 to-pink-500/20 border-purple-500/20',
    orange: 'from-orange-500/20 to-red-500/20 border-orange-500/20',
  }

  const iconColorClasses = {
    emerald: 'text-emerald-500',
    blue: 'text-blue-500',
    purple: 'text-purple-500',
    orange: 'text-orange-500',
  }

  return (
    <motion.div
      className={`glass p-6 rounded-2xl border border-white/10 bg-gradient-to-br ${colorClasses[color]}`}
      initial={{ opacity: 0, y: 20 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ delay, duration: 0.4 }}
      whileHover={{ scale: 1.02 }}
    >
      <div className="flex items-start justify-between">
        <div className="flex-1">
          <p className="text-sm font-medium text-muted-foreground mb-2">{label}</p>
          <div className="flex items-baseline gap-2">
            <h3 className="text-3xl font-bold text-foreground">
              <AnimatedCounter value={value} suffix={suffix} />
            </h3>
            {trend !== undefined && (
              <span className="text-sm font-semibold text-emerald-500">
                +{trend}%
              </span>
            )}
          </div>
          {trend && (
            <p className="text-xs text-muted-foreground mt-2">
              vs last month
            </p>
          )}
        </div>
        <div className={`p-3 rounded-lg bg-white/10 ${iconColorClasses[color]}`}>
          {icon}
        </div>
      </div>
    </motion.div>
  )
}

export function StatsSection() {
  const stats = [
    {
      icon: <Leaf size={24} />,
      label: 'Total Food Donated',
      value: 1240,
      suffix: ' kg',
      trend: 15,
      color: 'emerald',
    },
    {
      icon: <Users size={24} />,
      label: 'People Helped',
      value: 3420,
      trend: 22,
      color: 'blue',
    },
    {
      icon: <TrendingUp size={24} />,
      label: 'Donations This Month',
      value: 28,
      trend: 8,
      color: 'purple',
    },
    {
      icon: <Heart size={24} />,
      label: 'Carbon Saved (kg CO₂)',
      value: 2840,
      trend: 18,
      color: 'orange',
    },
  ]

  return (
    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 mb-8">
      {stats.map((stat, index) => (
        <StatCard key={stat.label} {...stat} delay={index * 0.1} />
      ))}
    </div>
  )
}
